// Product.java (entity)
@Entity
public class Product {
    
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;
    
    private String name;
    
    private String description;
    
    // getters and setters
    
}

// ProductService.java (service)
@Service
public class ProductService {
    
    @Autowired
    private ElasticsearchTemplate elasticsearchTemplate;
    
    public void indexProduct(Product product) {
        Map<String, Object> jsonMap = new HashMap<>();
        jsonMap.put("name", product.getName());
        jsonMap.put("description", product.getDescription());
        
        elasticsearchTemplate.index(Product.class, jsonMap);
    }
    
}

// ProductController.java (controller)
@RestController
@RequestMapping("/api/products")
public class ProductController {
    
    @Autowired
    private ProductService productService;
    
    @PostMapping
    public void indexProduct(@RequestBody Product product) {
        productService.indexProduct(product);
    }
    
    @GetMapping
    public List<Product> searchProducts(@RequestParam String query) {
        SearchQuery searchQuery = new NativeSearchQueryBuilder()
                .withQuery(QueryBuilders.queryStringQuery(query))
                .build();
        
        return elasticsearchTemplate.queryForList(searchQuery, Product.class);
    }
}

// ElasticsearchConfig.java (config)
@Configuration
public class ElasticsearchConfig {
    
    @Bean
    public RestHighLevelClient restHighLevelClient() {
        ClientConfiguration clientConfiguration = ClientConfiguration.builder()
                .connectedTo("localhost:9200")
                .build();
        
        return RestClients.create(clientConfiguration).restClient();
    }
}

// SecurityConfig.java (security)
@Configuration
@EnableWebSecurity
public class SecurityConfig extends WebSecurityConfigurerAdapter {
    
    @Override
    protected void configure(HttpSecurity http) throws Exception {
        http.csrf().disable()
                .authorizeRequests()
                .antMatchers("/api/products").permitAll()
                .anyRequest().authenticated();
    }
}